import { effect, inject, Injectable } from '@angular/core';
import { toSignal } from '@angular/core/rxjs-interop';
import { TranslateService } from '@ngx-translate/core';
import { map, startWith } from 'rxjs';
import { ClientDataService } from '../../features/clients/services/client-data.service';
import { AuthDataService } from './auth-data.service';

@Injectable({
  providedIn: 'root',
})
export class LanguageService {
  private readonly translate = inject(TranslateService);
  private readonly authDataService = inject(AuthDataService);
  private readonly clientDataService = inject(ClientDataService);
  private readonly SUPPORTED = ['en', 'fr', 'es', 'pt', 'nl', 'de', 'it'];
  private readonly DEFAULT = 'en';
  private readonly STORAGE_KEY = 'app-language';
  readonly currentLanguage = toSignal(
    this.translate.onLangChange.pipe(
      map((e) => e.lang),
      startWith(this.translate.getCurrentLang() ?? this.DEFAULT),
    ),
    { initialValue: this.DEFAULT },
  );

  constructor() {
    effect(() => {
      const client = this.clientDataService.getSelectedClientSignal()();
      this.setLanguage(
        client?.language ??
          sessionStorage.getItem(this.STORAGE_KEY) ??
          this.authDataService.profile()?.language ??
          navigator.language,
      );
    });
  }

  normalize(raw: string | null | undefined): string {
    const base = raw?.split('-')[0]?.toLowerCase();
    return this.SUPPORTED.includes(base ?? '') ? (base ?? '') : this.DEFAULT;
  }

  setLanguage(lang: string | null | undefined): void {
    this.translate.use(this.normalize(lang));
  }

  onManualLanguageChange(lang: string): void {
    sessionStorage.setItem(this.STORAGE_KEY, lang);
    this.setLanguage(lang);
  }
}
